const state = new GameState();

const server = http.createServer((req, res) => {
  if (req.url === '/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true, players: state.players.size, units: state.units.size, structures: state.structures.size }));
    return;
  }
  res.writeHead(404);
  res.end();
});

const wss = new WebSocket.Server({ server });

function send(ws, obj) {
  if (ws.readyState !== WebSocket.OPEN) return;
  ws.send(JSON.stringify(obj));
}

function broadcast(obj) {
  const data = JSON.stringify(obj);
  for (const client of wss.clients) {
    if (client.readyState === WebSocket.OPEN) client.send(data);
  }
}

function minimalDelta() {
  const units = [];
  for (const u of state.units.values()) {
    units.push(pick(u, ['id', 'ownerId', 'type', 'x', 'y', 'hp', 'maxHp', 'targetPos', 'targetId', 'state']));
  }
  const structures = [];
  for (const s of state.structures.values()) {
    structures.push(pick(s, ['id', 'ownerId', 'type', 'x', 'y', 'hp', 'maxHp', 'complete', 'buildDoneAt']));
  }
  const players = [];
  for (const p of state.players.values()) {
    players.push({ id: p.id, name: p.name, resources: p.resources, connected: p.connected });
  }
  return { t: 'state', seq: state.seq, serverTime: nowMs(), players, units, structures };
}

wss.on('connection', (ws) => {
  ws.binaryType = 'arraybuffer';

  let player = null;

  ws.on('message', (data) => {
    const text = typeof data === 'string' ? data : Buffer.isBuffer(data) ? data.toString('utf8') : '';
    const msg = safeJsonParse(text);
    if (!msg) return;

    if (!player) {
      if (msg.t === 'join') {
        const name = typeof msg.name === 'string' ? msg.name : 'Player';
        const p = state.addPlayer({ name });
        if (!p) {
          send(ws, { t: 'error', code: 'server_full' });
          ws.close();
          return;
        }
        player = p;
        player.socket = ws;

        send(ws, { t: 'welcome', playerId: player.id, serverTime: nowMs(), map: MAP, tickRate: TICK_RATE });
        send(ws, state.snapshotForPlayer(player.id));
        broadcast({ t: 'player_joined', player: { id: player.id, name: player.name, resources: player.resources, connected: true } });
        return;
      } else {
        send(ws, { t: 'error', code: 'must_join_first' });
        return;
      }
    }

    if (msg.t === 'ping') {
      send(ws, { t: 'pong', serverTime: nowMs() });
      return;
    }

    state.handleCommand(player.id, msg);
  });

  ws.on('close', () => {
    if (player) {
      state.removePlayer(player.id);
      broadcast({ t: 'player_left', playerId: player.id });
    }
  });

  ws.on('error', () => {});
});

let lastBroadcastAt = nowMs();
let lastTickAt = nowMs();

setInterval(() => {
  const t = nowMs();
  const dt = Math.min(250, Math.max(0, t - lastTickAt));
  lastTickAt = t;

  state.tick(dt);

  if (t - lastBroadcastAt >= 100) {
    lastBroadcastAt = t;
    broadcast(minimalDelta());
  }
}, TICK_MS);

server.listen(PORT, () => {
  console.log(`RTS WebSocket server listening on :${PORT}`);
});